import LocalAuthentication
import SwiftUI

class AuthManager: ObservableObject {
    @Published var isUnlocked = false
    @Published var biometricsAvailable = false
    @Published var errorMessage: String?

    func checkBiometrics() {
        let context = LAContext()
        var error: NSError?
        biometricsAvailable = context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }

    func authenticate() {
        let context = LAContext()
        context.localizedFallbackTitle = "Use Passcode"

        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: "Unlock your data") { [weak self] success, error in
            DispatchQueue.main.async {
                if success {
                    self?.isUnlocked = true
                    self?.errorMessage = nil
                } else if let error = error as? LAError {
                    switch error.code {
                    case .userCancel:
                        self?.errorMessage = nil
                    case .userFallback:
                        self?.errorMessage = "Enter your passcode"
                    case .biometryNotEnrolled:
                        self?.errorMessage = "No biometrics enrolled. Go to Settings to set up."
                    default:
                        self?.errorMessage = "Authentication failed"
                    }
                }
            }
        }
    }

    func lock() {
        isUnlocked = false
    }
}
